import{_ as o,H as i,o as l,c as u,S as r,J as a,C as s,a as t}from"./chunks/framework.97ee81d9.js";const v=JSON.parse('{"title":"Plateforme de données dans une organisation polycéphale - Partie 1 🎯","description":"","frontmatter":{"date":"2025-07-02T00:00:00.000Z","title":"Plateforme de données dans une organisation polycéphale - Partie 1 🎯","sidebar":false,"author":"Martin Erpicum","category":"Article","tags":["data","orchestrator"],"blog":"post","aside":"left","prev":false,"next":false},"headers":[],"relativePath":"blog/posts/2025/data_platform_in_fwb_00_intro-fr.md"}'),d={name:"blog/posts/2025/data_platform_in_fwb_00_intro-fr.md"};function p(c,e,m,g,f,b){const n=i("ImageCenter");return l(),u("div",null,[e[0]||(e[0]=r('<p><em>Résumé exécutif</em> : Dans une organisation polycéphale, la Gouvernance des Données est un défi complexe. Cet article explore la mise en œuvre d&#39;une Plateforme de Données basée sur <a href="https://dagster.io/" target="_blank" rel="noreferrer">Dagster</a> pour la <a href="https://www.federation-wallonie-bruxelles.be" target="_blank" rel="noreferrer">Fédération Wallonie-Bruxelles (FWB)</a>. Il met en évidence l&#39;importance de l&#39;automatisation, de la modularité et de la réutilisabilité des composants pour abaisser la barrière technique et améliorer la littératie des données parmi les analystes de données et les gestionnaires de données.</p><hr><p><em>Les opinions exprimées sur ce site web sont les miennes et ne reflètent pas nécessairement celles de mon employeur.</em></p><p><strong>Table des matières</strong></p><nav class="table-of-contents"><ul><li><a href="#🏛️-contexte">🏛️ Contexte</a></li><li><a href="#🎯-quelle-est-notre-strategie-de-donnees">🎯 Quelle est notre stratégie de données ?</a></li><li><a href="#📦-ou-sont-les-donnees">📦 Où sont les données ?</a></li><li><a href="#🏗️-quelle-est-notre-pile-de-donnees">🏗️ Quelle est notre pile de données ?</a></li><li><a href="#🤖-automatiser-tout-ou-presque-faciliter-l-integration">🤖 Automatiser tout (ou presque) : faciliter l&#39;intégration</a></li><li><a href="#📚-litteratie-des-donnees-abaisser-la-barriere-et-donner-du-pouvoir-aux-utilisateurs">📚 Littératie des données : Abaisser la barrière et donner du pouvoir aux utilisateurs</a></li></ul></nav><h2 id="🏛️-contexte" tabindex="-1">🏛️ Contexte <a class="header-anchor" href="#🏛️-contexte" aria-label="Permalink to &quot;🏛️ Contexte&quot;">​</a></h2><p>La Communauté française de Belgique (ou Fédération Wallonie-Bruxelles, FWB) désigne l&#39;une des trois communautés linguistiques constitutionnelles de Belgique.</p><p>La Communauté française de Belgique comprend <em>~4,5 millions</em> de personnes et son administration est responsable de la gestion de l&#39;enseignement, de la culture, du sport, de l&#39;aide à la jeunesse, des relations internationales, etc. pour la population francophone du pays. L&#39;administration elle-même emploie plus de <em>7 000</em> personnes, mais le nombre d&#39;employés du secteur public qui dépendent directement de la FWB est beaucoup plus élevé, principalement en raison des secteurs de l&#39;enseignement et de la garde d&#39;enfants.</p>',8)),a(n,{src:"https://raw.githubusercontent.com/data-cfwb/charte-graphique/refs/heads/main/logo_FWB_PNG_et_SVG/FWBCOUL_FWB_HORI.png",alt:"",width:"400"}),e[1]||(e[1]=s("p",null,[t("Le Ministère de la FWB (MFWB) est une organisation complexe avec plusieurs entités appelées "),s("strong",null,'"Administrations générales"'),t(" (ou "),s("strong",null,"AG"),t("). Chacune de ces entités gère ses propres données — souvent en silos — et possède ses propres structures de gouvernance composées de diverses couches de Services et Directions avec des Chefs de projet, des Product Owners, des Analystes métier, etc. Sous cette complexité organisationnelle, le "),s("strong",null,"paysage technique"),t(" est bien sûr également complexe. Chaque AG a ses propres produits, applications, SGBD, DWH, outils BI, etc. Cela conduit à un manque de cohérence et de qualité dans les données. Les employés utilisent principalement des produits Microsoft ("),s("em",null,"Excel"),t(") pour leurs besoins en gestion et analyse de données. Très peu de personnes sont formées à la gestion des données et à la programmation, ce qui conduit parfois à un manque de compréhension de l'importance de la gouvernance des données.")],-1)),e[2]||(e[2]=s("blockquote",null,[s("p",null,"La nature polycéphale de l'organisation rend difficile la gouvernance et la mise en œuvre d'une plateforme de données unifiée répondant aux besoins de toutes les parties prenantes.")],-1)),a(n,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/images/data_gov_fwb.png",alt:"",width:"400"}),e[3]||(e[3]=r('<h2 id="🎯-quelle-est-notre-strategie-de-donnees" tabindex="-1">🎯 Quelle est notre stratégie de données ? <a class="header-anchor" href="#🎯-quelle-est-notre-strategie-de-donnees" aria-label="Permalink to &quot;🎯 Quelle est notre stratégie de données ?&quot;">​</a></h2><p>La stratégie de données de la Communauté française de Belgique (FWB), connue sous le nom de &quot;Données au Centre&quot;, est en place depuis 2020 et vise à améliorer la gestion et l&#39;exploitation des données pour améliorer la prestation de services et la gouvernance.</p><p>Les éléments clés de la stratégie incluent :</p><ul><li>Attribuer un <strong>Data Owner et un Data Steward</strong> à chaque ensemble de données significatif pour assurer la responsabilité et une gestion appropriée.</li><li>Fournir un <strong>accès brut</strong> aux ensembles de données pour le personnel autorisé, tout en respectant les exigences de conformité légale obligatoires.</li><li>Offrir une <strong>formation</strong> technique et non technique aux Data Owners et Data Stewards sur des sujets tels que les indicateurs de données, la visualisation, la gouvernance, Python et SQL pour améliorer leurs compétences en gestion de données.</li><li>Cultiver une <strong>culture centrée sur les données</strong> (Données au centre) grâce à une <strong>documentation</strong> complète, une formation et des <strong>réunions communautaires régulières</strong> pour encourager l&#39;utilisation efficace des ressources de données.</li></ul><p>La stratégie décrit des objectifs axés sur l&#39;amélioration de la qualité, de la disponibilité et de la sécurité des données, et sur la promotion de la collaboration au-delà des frontières organisationnelles. Elle cherche à identifier les actifs de données stratégiques cruciaux pour les opérations du ministère, à développer des tableaux de bord stratégiques et opérationnels pour une prise de décision éclairée, et à promouvoir le partage et la réutilisation des données au-delà des barrières organisationnelles.</p><p>De plus, la stratégie priorise la conformité RGPD pour les données personnelles, l&#39;intégration des données de référence dans les solutions métier, et la publication des données via la <a href="https://www.odwb.be" target="_blank" rel="noreferrer">plateforme Open Data</a> pour améliorer la transparence et l&#39;accessibilité.</p><h2 id="📦-ou-sont-les-donnees" tabindex="-1">📦 Où sont les données ? <a class="header-anchor" href="#📦-ou-sont-les-donnees" aria-label="Permalink to &quot;📦 Où sont les données ?&quot;">​</a></h2><p>Dans le contexte de ce type d&#39;organisation, les <strong>données brutes</strong> sont collectées à partir de diverses sources, notamment des bases de données, des API et des fichiers plats. La nature hétérogène de ces sources rend difficile la garantie de l&#39;accès aux données, de leur qualité, de leur cohérence — et donc de leur exploitation. Pour relever ce défi, une décision prise il y a des années a été de mettre en œuvre une couche de virtualisation (basée sur <a href="https://www.denodo.com/" target="_blank" rel="noreferrer">Denodo</a>) au-dessus des SGBD.</p><p>Denodo est un outil puissant pour la virtualisation des données, mais il nécessite un certain niveau d&#39;expertise pour la configuration et la maintenance. Cela peut être un obstacle pour certaines équipes, en particulier celles disposant de ressources techniques limitées. Il n&#39;est pas non plus 100% conforme à la plupart des standards SQL (Denodo VQL), ce qui peut entraîner de la confusion et des erreurs lors du travail avec les données (à travers les systèmes en amont et en aval).</p>',9)),a(n,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/diagrams/fwb_datalake.drawio.png",alt:"",width:"400"}),e[4]||(e[4]=r('<h2 id="🏗️-quelle-est-notre-pile-de-donnees" tabindex="-1">🏗️ Quelle est notre pile de données ? <a class="header-anchor" href="#🏗️-quelle-est-notre-pile-de-donnees" aria-label="Permalink to &quot;🏗️ Quelle est notre pile de données ?&quot;">​</a></h2><p>Une pile de données est généralement composée de plusieurs composants qui fonctionnent ensemble pour gérer et traiter les données. Les composants spécifiques d&#39;une pile de données peuvent varier en fonction des besoins de l&#39;organisation, mais ils incluent généralement :</p><ul><li><strong>Sources</strong> : Ce sont les systèmes et applications qui génèrent et stockent des données. Ils peuvent inclure des bases de données, des API, des fichiers plats et d&#39;autres référentiels de données.</li><li><strong>Plateforme</strong> : C&#39;est là que le calcul est effectué pour traiter et analyser les données. Elle peut inclure des plateformes basées sur le cloud, des serveurs sur site et d&#39;autres ressources informatiques.</li><li><strong>Stockage</strong> : C&#39;est là que les données sont stockées pour une utilisation ultérieure. Il peut inclure des bases de données, des lacs de données et d&#39;autres solutions de stockage.</li><li><strong>Traitement</strong> : C&#39;est là que les données sont transformées et préparées pour l&#39;analyse. Il peut inclure des processus ETL (Extract, Transform, Load), des pipelines de données et d&#39;autres outils de traitement de données. Cela inclut également les processus ML et AI qui peuvent être utilisés pour analyser et extraire des insights des données.</li><li><strong>Tableau de bord</strong> : C&#39;est là que les données sont présentées d&#39;une manière facile à comprendre et à analyser. Il peut inclure des tableaux de bord, des rapports et d&#39;autres outils de visualisation.</li></ul><p>Notre pile de données comprend actuellement plusieurs composants :</p>',4)),a(n,{src:"https://raw.githubusercontent.com/tintamarre/tintamarre.github.io/refs/heads/master/src/assets/diagrams/fwb_tech_stack.drawio.png",alt:"",width:"600"}),e[5]||(e[5]=r('<p>Nous avons également essayé plusieurs outils avant de nous arrêter sur ce que nous avons aujourd&#39;hui. L&#39;objectif était de trouver une solution qui soit flexible, auditable, transparente et évolutive. Par &quot;auditable&quot;, nous entendons un système où chaque action et modification peut être suivie, enregistrée et examinée pour garantir la responsabilité et la conformité.</p><p>Nous voulions également éviter le <em>vendor lock-in</em> 🔒 et nous assurer que la solution pourrait être adaptée aux besoins de l&#39;organisation et au niveau d&#39;expertise technique des utilisateurs.</p><p>Sur la base de ces exigences, en termes d&#39;orchestrateurs, nous avons essayé <strong>Airflow</strong> pendant quelques semaines et nous nous sommes appuyés sur <strong>Prefect</strong> pendant quelques mois. Nous avons ensuite décidé de passer à <strong>Dagster</strong>, pour un ensemble de raisons :</p><ul><li>Fonctionnalités d&#39;<strong>observabilité des données</strong> au cœur de l&#39;architecture -- c&#39;est une exigence clé pour nous ;</li><li>Séparation de l&#39;<strong>emplacement du code pour correspondre à la nature fortement décentralisée</strong> de la FWB ;</li><li>Grande communauté et <strong>documentation qualitative unifiée</strong> ;</li></ul><p>La nouvelle architecture comprend une plateforme de données qui s&#39;intègre aux sources de données et outils existants, offrant une approche plus rationalisée et efficace de la gestion des données.</p><p>Sur la base de notre contexte et de nos choix, la mise en œuvre d&#39;un orchestrateur de données réussi pour la FWB repose sur deux défis clés : <strong>l&#39;onboarding facile</strong> et la <strong>littératie des données</strong> de nos utilisateurs. Pour y parvenir, nous devons nous concentrer sur les aspects suivants :</p><h2 id="🤖-automatiser-tout-ou-presque-faciliter-l-integration" tabindex="-1">🤖 Automatiser tout (ou presque) : faciliter l&#39;intégration <a class="header-anchor" href="#🤖-automatiser-tout-ou-presque-faciliter-l-integration" aria-label="Permalink to &quot;🤖 Automatiser tout (ou presque) : faciliter l&#39;intégration&quot;">​</a></h2><p>Développer un logiciel comme une plateforme de données est une tâche complexe qui nécessite beaucoup de temps et d&#39;efforts. Pour faciliter l&#39;intégration et l&#39;utilisation de la plateforme par les utilisateurs, nous devons nous concentrer sur l&#39;automatisation du processus autant que possible. Voici un aperçu de notre stratégie d&#39;automatisation :</p><ul><li><strong>Automatiser les tests</strong> : Mise en œuvre de tests complets, des tests unitaires aux tests d&#39;intégration</li><li><strong>Automatiser le déploiement</strong> : Pipeline de déploiement multi-environnement (test, staging, production)</li><li><strong>Automatiser l&#39;intégration</strong> : Connexion transparente avec les systèmes existants de la FWB</li><li><strong>Automatiser la surveillance</strong> : Surveillance proactive du pipeline et de la qualité des données</li></ul><blockquote><p>💡 Pour une plongée détaillée dans notre implémentation de l&#39;automatisation, y compris les configurations GitLab CI/CD et des exemples d&#39;assets Dagster, consultez la partie 2 de cette série.</p></blockquote><ul><li><a href="/blog/posts/2025/data_platform_in_fwb_01_automate-fr.html">Partie 2 : Plongée approfondie dans notre stratégie d&#39;automatisation avec des exemples pratiques GitLab CI/CD</a></li></ul><h2 id="📚-litteratie-des-donnees-abaisser-la-barriere-et-donner-du-pouvoir-aux-utilisateurs" tabindex="-1">📚 Littératie des données : Abaisser la barrière et donner du pouvoir aux utilisateurs <a class="header-anchor" href="#📚-litteratie-des-donnees-abaisser-la-barriere-et-donner-du-pouvoir-aux-utilisateurs" aria-label="Permalink to &quot;📚 Littératie des données : Abaisser la barrière et donner du pouvoir aux utilisateurs&quot;">​</a></h2><p>Comme la plupart de nos utilisateurs ne sont pas des professionnels de la donnée formés, nous avons développé plusieurs stratégies pour rendre la plateforme plus accessible :</p><ul><li><strong>Réduction de la barrière technique</strong> : Interfaces et workflows conviviaux</li><li><strong>Développement de ressources de base</strong> : Composants et modèles réutilisables</li><li><strong>Cadre de bonnes pratiques</strong> : Normes claires pour le codage, les tests et le déploiement</li><li><strong>Intégration de l&#39;IA</strong> : Tirer parti de l&#39;IA pour l&#39;assistance au développement de pipelines</li><li><strong>Architecture de code modulaire</strong> : Emplacements de code indépendants pour une complexité réduite</li></ul><blockquote><p>💡 Dans la partie 3 de cette série, nous explorerons comment nos ressources personnalisées ont amélioré la gouvernance des données et rendu la plateforme plus accessible aux utilisateurs de tous les niveaux techniques.</p></blockquote><ul><li><a href="/blog/posts/2025/data_platform_in_fwb_02_lower_barrier-fr.html">Partie 3 : Comment les ressources personnalisées et la formation aident à abaisser la barrière</a></li></ul>',16))])}const q=o(d,[["render",p]]);export{v as __pageData,q as default};
